#include<bits/stdc++.h>
using namespace std;
long long p[1000010],v[1000010],tot;
struct node
{
    long long l,r;
    bool operator<(const node&b)const
    {
        return r<b.r;
    }
}a[1000010];
long long l[1000010],r[1000010],s[1000010],sum[1000010];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&a[i].l,&a[i].r);
        a[i].r--;
        v[++tot]=a[i].l;
        v[++tot]=a[i].l-1;
        v[++tot]=a[i].r;
        v[++tot]=a[i].r+1;
    }
    v[++tot]=0;
    v[++tot]=1;
    sort(v+1,v+1+tot);
    sort(a+1,a+1+n);
    for(long long i=1;i<=n;i++)
    {
        l[i]=a[i].l;
        r[i]=a[i].r;
    }
    tot=unique(v+1,v+1+tot)-v-1;
    for(long long i=1;i<=n;i++)
    {
        l[i]=lower_bound(v+1,v+1+tot,l[i])-v;
        r[i]=lower_bound(v+1,v+1+tot,r[i])-v;
        s[l[i]]++;
        s[r[i]+1]--;
    }
    long long ans=0,ans1=0;
    for(long long i=1;i<=tot;i++)
    {
        s[i]+=s[i-1];
        if(s[i]==1)
        {
            sum[i]=sum[i-1]+(v[i]-v[i-1]);
        }
        else
        {
            sum[i]=sum[i-1];
        }
        if(s[i])
        {
            ans+=v[i]-v[i-1];
        }
    }
    for(long long i=1;i<=n;i++)
    {
        ans1=max(ans1,ans-sum[r[i]]+sum[l[i]-1]);
    }
    printf("%lld",ans1);
    return 0;
}
